async function handleFileSelect(event) {
    const files = event.target.files;
    if (files.length < 1) return;

    let koFile = null;
    let enFile = null;

    for (const file of files) {
        const fileName = file.name.toLowerCase();
        if (fileName.includes('.ko.srt') || fileName.includes('.ko.txt')) {
            koFile = file;
        } else if (fileName.includes('.en.srt') || fileName.includes('.en.txt')) {
            enFile = file;
        }
    }

    if (koFile && enFile) {
        await loadAndProcessFiles(koFile, enFile);
    } else {
        subtitleList.innerHTML = `<p class="info-msg" style="color: #dc3545;">파일명에 '.ko.srt'와 '.en.srt'가 포함된<br>두 개의 파일을 동시에 선택해주세요.</p>`;
    }
}

